SELECT

FROM product_info
WHERE deleted = 0
  AND on_shelf = 1
  AND product_status = 'PUBLISHED'

    AND (
        CAST(product_id AS CHAR) LIKE CONCAT('%', #{keyword}, '%')
        OR title LIKE CONCAT('%', #{keyword}, '%')
        OR category LIKE CONCAT('%', #{keyword}, '%')
        OR condition_level LIKE CONCAT('%', #{keyword}, '%')
        OR trade_location LIKE CONCAT('%', #{keyword}, '%')
        OR description LIKE CONCAT('%', #{keyword}, '%')
    )


    AND category = #{category}


    AND condition_level = #{conditionLevel}


    AND trade_location = #{tradeLocation}


    AND price >= #{minPrice}


    AND price <= #{maxPrice}



        ORDER BY price ASC, create_time DESC


        ORDER BY price DESC, create_time DESC


        ORDER BY create_time DESC


LIMIT #{offset}, #{limit}

